// Example Pixel Shader

// TD Panel Functions

// vec2 TDPanelSize() - returns the size in panel units

// vec2 TDPanelUV() - returns the current pixel in uv coordinates
// vec2 TDPanelPos() - returns the current pixel in panel units

// float TDPanelInside() - returns 1 if the cursor is inside the panel, 0 otherwise
// vec2 TDPanelMousePos() - returns the position of the mouse inside the panel in panel units
// vec2 TDPanelMouseUV() - returns the position of the mouse inside the panel in uv coordinates

// float TDPanelSelect() - returns 1 if any button is down inside the panel, 0 otherwise
// float TDPanelSelectLeft() - returns 1 if the left mouse button is down inside the panel, 0 otherwise
// float TDPanelSelectMiddle() - returns 1 if the middle mouse button is down inside the panel, 0 otherwise
// float TDPanelSelectRight() - returns 1 if the right mouse button is down inside the panel, 0 otherwise

// float TDPanelPixelSize() - returns the size of a pixel in panel units
// float TDPanelUVPixelSize() - returns the size of a pixel in uv coordinates

float roundedBoxSDF(vec2 p, vec2 Center, vec2 Size, float Radius)
{
	return length(max(abs(p - Center) - (Size/2) + Radius, 0.0)) - Radius;
}

out vec4 oFragColor;
void main()
{
	float   rad = 30;
	vec2	size = TDPanelSize();

	// distance of current pixel within the button
	float   d = roundedBoxSDF(TDPanelPos(), size/2, size*vec2(0.7, 0.3), rad);

	// default foreground color
	vec4	fgColor = vec4(0.5,0.5,0.5,1);

	// distance of the mouse within the button
	float   md = roundedBoxSDF(TDPanelMousePos(), size/2, size*vec2(0.7, 0.3), rad);

	// check if the mouse is over the panel and inside the rectangle
	if( TDPanelInside() > 0 && md < 0 )
	{
		// is the select button pressed
		if( TDPanelSelect() > 0 )
			fgColor = vec4(0.3,0.3,0.3,1);
		else
			fgColor = vec4(0.8,0.8,0.8,1);
	}

	// blend a border around the edge of the button
	float 	borderBlend = smoothstep(-4, -4 - TDPanelPixelSize(), d);
	vec4	borderColor = vec4(1,1,1,1);
	vec4	color = mix( borderColor, fgColor, borderBlend );

	// blend the edges of the button
	float 	edgeBlend = smoothstep(0.0f, -1.0 * TDPanelPixelSize(), d);
	color = vec4( color.rgb * edgeBlend, edgeBlend );

	oFragColor = TDOutputSwizzle(color);
}

